class Solution:
    def countPalindromicSubsequence(self, s):
        found = set()
        n = len(s)
        for i in range(n):
            for k in range(i + 2, n):
                if s[i] == s[k]:
                    for j in range(i + 1, k):
                        found.add((s[i], s[j]))
        return len(found)

