var countPalindromicSubsequence = function(s) {
    const first = {}, last = {};
    for (let i = 0; i < s.length; i++) {
        if (!(s[i] in first)) first[s[i]] = i;
        last[s[i]] = i;
    }
    let total = 0;
    for (const c of Object.keys(first)) {
        const f = first[c], l = last[c];
        if (l - f >= 2) {
            const mids = new Set();
            for (let i = f + 1; i < l; i++) mids.add(s[i]);
            total += mids.size;
        }
    }
    return total;
};
